const response = $input.first().json;
const refunds = response.data || response.refund_requests || response || [];

if (!Array.isArray(refunds) || refunds.length === 0) return [];

const lines = refunds.map(r =>
  `• ${r.customer_email || r.email || 'N/A'} — ${r.product_name || r.product || 'N/A'} (${r.amount ? r.amount/100 : '?'} ${r.currency || ''})`
).join('\n');

const msg = `⚠️ *Pending Refund Requests: ${refunds.length}*\n\n${lines}\n\n👉 Sprawdź w panelu admina`;

return [{ json: { message: msg, count: refunds.length } }];
